(function(){var loadHandler=window['sl_{9450D772-0E62-4F6B-A391-1A4C67BA4AE3}'];loadHandler&&loadHandler(61, '<div id="spr0_d0abcc"><div id="spr1_d0abcc" class="kern slide"><img id="img4_d0abcc" src="data:image/png;base64," width="960px" height="540px" alt="" style="left:0px;top:0px;"/><div id="spr3_d0abcc" style="left:894px;"><a id="hl0_d0abcc" href="#" onclick="document.getElementById(\'coreSpr_13639734\').getCore().processTriggerEffect(this);document.getElementById(\'coreSpr_13639734\').getCore().gotoFirstSlide(this);return false;"><img id="img0_d0abcc" src="data:image/png;base64," width="65" height="66" alt="" style="left:0.138px;top:0.077px;"/></a></div><div id="spr4_d0abcc" style="left:726.612px;top:8.765px;"><img id="img1_d0abcc" src="data:image/png;base64," width="185" height="45" alt="A close-up of a pen  AI-generated content may be incorrect." style="left:0.071px;top:-0.07px;"/></div></div><div id="spr2_d0abcc" class="kern slide"><div id="spr5_d0abcc" style="left:49px;top:12.75px;"><div style="width:0px;"><span id="txt0_d0abcc" data-width="608.193359" style="left:110.892px;top:-4.1px;">FROST POCKETS, AND RADIATION FOG</span></div></div><div id="spr6_d0abcc" style="top:60.213px;"><div style="width:0px;"><span id="txt1_d0abcc" class="nokern relpos" dir="auto" style="left:7.249px;top:1.691px;"></span> <span id="txt2_d0abcc" class="relpos" data-width="60.416016" style="left:7.249px;top:-2.889px;">Both </span> <span id="txt3_d0abcc" class="relpos" data-width="794.404297" style="left:7.244px;top:-2.889px;">frost and fog are types of condensation that occur in valley climates.</span></div><div style="width:0px;"><span id="txt4_d0abcc" class="nokern relpos" dir="auto" style="left:7.2px;top:41.295px;">•</span> <span id="txt5_d0abcc" class="relpos" data-width="58.734375" style="left:15.397px;top:37.351px;">Frost</span> <span id="txt6_d0abcc" class="relpos" data-width="144.703125" style="left:15.392px;top:37.351px;"> forms if the </span> <span id="txt7_d0abcc" class="relpos" data-width="124.332031" style="left:15.387px;top:37.351px;">dew point </span> <span id="txt8_d0abcc" class="relpos" data-width="521.787109" style="left:15.382px;top:37.351px;">is below 0°C. The coldest air collects in dips or</span></div><div style="width:0px;"><span id="txt9_d0abcc" class="relpos" data-width="334.441406" style="left:25.2px;top:67.591px;">hollows in the ground, called </span> <span id="txt10_d0abcc" class="relpos" data-width="158.757813" style="left:25.195px;top:67.591px;">frost pockets.</span></div><div style="width:0px;"><span id="txt11_d0abcc" class="nokern relpos" dir="auto" style="left:7.2px;top:111.775px;">•</span> <span id="txt12_d0abcc" class="relpos" data-width="41.179688" style="left:15.397px;top:107.831px;">Fog</span> <span id="txt13_d0abcc" class="relpos" data-width="411.195313" style="left:15.392px;top:107.831px;"> forms if the dew point is above 0°C.</span></div><div style="width:0px;"><span id="txt14_d0abcc" class="nokern relpos" dir="auto" style="left:7.2px;top:152.015px;">•</span> <span id="txt15_d0abcc" class="relpos" data-width="341.974609" style="left:15.397px;top:148.071px;">This common type of fog AKA </span> <span id="txt16_d0abcc" class="relpos" data-width="156.009766" style="left:15.392px;top:148.071px;">radiation fog </span> <span id="txt17_d0abcc" class="relpos" data-width="410.251953" style="left:15.387px;top:148.071px;">- is produced by terrestrial radiation</span></div><div style="width:0px;"><span id="txt18_d0abcc" data-width="874.371094" style="left:25.2px;top:178.311px;">on clear, calm nights, when the ground radiates (loses) heat and cools the air</span></div><div style="width:0px;"><span id="txt19_d0abcc" data-width="98.669922" style="left:25.2px;top:208.551px;">above it.</span></div><div style="width:0px;"><span id="txt20_d0abcc" class="nokern relpos" dir="auto" style="left:7.2px;top:252.735px;">•</span> <span id="txt21_d0abcc" class="relpos" data-width="912.378906" style="left:15.397px;top:248.791px;">The fog clears early in the morning as the Sun warms the air, making the air able</span></div><div style="width:0px;"><span id="txt22_d0abcc" data-width="263.935547" style="left:25.2px;top:279.031px;">to hold more moisture.</span></div></div><div id="spr7_d0abcc" style="left:379px;top:352px;"><img id="img2_d0abcc" src="data:image/png;base64," width="300" height="178" alt="Related image"/></div><div id="spr8_d0abcc" style="left:678.04px;top:359.07px;"><img id="img3_d0abcc" src="data:image/png;base64," width="282" height="188" alt="" style="left:-0.02px;top:-0.013px;"/></div></div></div>', '{"s":[]}');})();